MAGIC = b"GSS1"
OP_STATUS_QUERY = 0x01
OP_STATUS_RESPONSE = 0x81
OP_ERROR = 0xFF

FLAG_COMPRESSED = 0x01
FLAG_FRAGMENTED = 0x02

DEFAULT_MAX_DATAGRAM = 1200
DEFAULT_FRAGMENT_SIZE = 1000
DEFAULT_MAX_PAYLOAD = 2 * 1024 * 1024

def now_ms() -> int:
    return int(time.time() * 1000)

def clamp(n: int, lo: int, hi: int) -> int:
    return lo if n < lo else hi if n > hi else n

def ip_str(addr: Tuple[str, int]) -> str:
    return f"{addr[0]}:{addr[1]}"

def safe_json_dumps(obj: Any) -> bytes:
    return json.dumps(obj, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

def crc32_u32(data: bytes) -> int:
    return zlib.crc32(data) & 0xFFFFFFFF

def pack_header(op: int, flags: int, req_id: int, seq: int = 0, total: int = 1, payload_len: int = 0) -> bytes:
    # Header (fixed 20 bytes):
    # magic(4) ver(1) op(1) flags(1) rsv(1) req_id(4) seq(2) total(2) payload_len(4)
    ver = 1
    rsv = 0
    return struct.pack("!4sBBBBIHHI", MAGIC, ver, op, flags, rsv, req_id, seq, total, payload_len)

def unpack_header(data: bytes) -> Optional[Tuple[int, int, int, int, int, int]]:
    if len(data) < 20:
        return None
    magic, ver, op, flags, rsv, req_id, seq, total, payload_len = struct.unpack("!4sBBBBIHHI", data[:20])
    if magic != MAGIC or ver != 1:
        return None
    return op, flags, req_id, seq, total, payload_len

def build_error(req_id: int, code: str, message: str) -> bytes:
    payload = safe_json_dumps({"ok": False, "error": {"code": code, "message": message}})
    flags = 0
    hdr = pack_header(OP_ERROR, flags, req_id, 0, 1, len(payload))
    return hdr + payload

